        function rankHomepageHighlights() {
            const track = document.getElementById('homepage-featured-track');
            if (!track) return;
            const cards = Array.from(track.querySelectorAll('.homepage-highlight-card'));
            const policyEl = document.getElementById('homepage-ranking-policy');
            let policy = { newContentPriorityDays: 7, scoreWeights: { clicks: 2, reads: 0.2, conversions: 50, manualRecommendation: 150 } };
            if (policyEl) {
                try { policy = JSON.parse(policyEl.textContent); } catch (e) {}
            }
            const now = new Date();
            cards.forEach(card => {
                const published = new Date(`${card.dataset.published}T00:00:00`);
                const ageDays = Math.max(0, Math.floor((now - published) / 86400000));
                const isNew = ageDays <= policy.newContentPriorityDays;
                const clicks = Number(card.dataset.clicks || 0);
                const reads = Number(card.dataset.reads || 0);
                const conversions = Number(card.dataset.conversions || 0);
                const manual = card.dataset.recommended === 'true';
                const baseScore = clicks * policy.scoreWeights.clicks + reads * policy.scoreWeights.reads + conversions * policy.scoreWeights.conversions + (manual ? policy.scoreWeights.manualRecommendation : 0);
                const newBoost = isNew ? 100000 - (ageDays * 1000) : 0;
                const totalScore = baseScore + newBoost;
                card.dataset.rankScore = String(totalScore);
                const rankStatus = card.querySelector('.rank-status');
                const scoreSummary = card.querySelector('.score-summary');
                if (rankStatus) {
                    const daysLeft = Math.max(0, policy.newContentPriorityDays - ageDays);
                    rankStatus.textContent = isNew ? `New priority • ${daysLeft}d left` : (manual ? 'Weekly recommended' : 'Ranked by data');
                }
                if (scoreSummary) {
                    scoreSummary.textContent = `${clicks} clicks • ${reads} reads • ${conversions} leads`;
                }
            });
            cards.sort((a, b) => Number(b.dataset.rankScore) - Number(a.dataset.rankScore));
            cards.forEach(card => track.appendChild(card));
        }

        document.addEventListener('DOMContentLoaded', rankHomepageHighlights);

