(function(){
  window.scrollCarousel = function(containerId, direction) {
    const container = document.getElementById(containerId);
    if (!container) return;
    const firstCard = container.querySelector('.home-carousel-card');
    const cardWidth = firstCard ? firstCard.getBoundingClientRect().width : 0;
    const gap = parseFloat(getComputedStyle(container).columnGap || getComputedStyle(container).gap || 24) || 24;
    const scrollAmount = cardWidth ? (cardWidth + gap) : Math.max(container.clientWidth * 0.82, 280);
    container.scrollBy({ left: direction * scrollAmount, behavior: 'smooth' });
  };

  function initNanofixHomeCarousels() {
    document.querySelectorAll('.home-carousel-section [data-carousel-target]').forEach(function(btn){
      if (btn.dataset.carouselBound === 'true') return;
      btn.dataset.carouselBound = 'true';
      btn.addEventListener('click', function(e){
        e.preventDefault();
        e.stopPropagation();
        window.scrollCarousel(btn.getAttribute('data-carousel-target'), Number(btn.getAttribute('data-carousel-direction') || 1));
      });
    });

    document.querySelectorAll('.home-carousel-section [id$="-track"]').forEach(function(track){
      if (track.dataset.dragReady === 'true') return;
      track.dataset.dragReady = 'true';
      let isDown = false;
      let startX = 0;
      let scrollLeft = 0;
      let moved = false;

      track.addEventListener('pointerdown', function(e){
        if (e.pointerType === 'mouse' && e.button !== 0) return;
        isDown = true;
        moved = false;
        startX = e.clientX;
        scrollLeft = track.scrollLeft;
        track.classList.add('is-dragging');
        try { track.setPointerCapture(e.pointerId); } catch(_) {}
      });
